import requests

response = requests.post(
    "https://api.aimlapi.com/v2/video/generations",
    headers={
        "Authorization": "Bearer <YOUR_AIMLAPI_KEY>",
        "Content-Type": "application/json",
    },
    json={'model': 'beeble/switchx-video-to-video', 'video_url': 'https://example.com/input.jpg', 'prompt': 'Describe what you want the model to generate.'},
)

print(response.json())
